create table transactions
(
    id             bigint unsigned auto_increment
        primary key,
    created_at     datetime(3)     null comment '创建时间',
    updated_at     datetime(3)     null,
    deleted_at     datetime(3)     null,
    transaction_no varchar(64)     null comment '交易流水号',
    user_id        bigint unsigned null comment '用户ID',
    type           bigint          null comment '交易类型(1-充值 2-消费 3-退款 4-系统调账)',
    amount         decimal(20, 6)  null comment '交易金额(正数为收入,负数为支出)',
    balance_before decimal(20, 6)  null comment '交易前余额',
    balance_after  decimal(20, 6)  null comment '交易后余额',
    order_id       bigint unsigned null comment '关联订单ID',
    method         bigint          null comment '支付方式(1-支付宝 2-微信 3-余额 4-系统)',
    remark         varchar(500)    null comment '备注',
    constraint idx_transactions_transaction_no
        unique (transaction_no)
);

create index idx_transactions_deleted_at
    on transactions (deleted_at);

create index idx_transactions_user_id
    on transactions (user_id);

